import React, { useRef, useEffect, useState } from 'react';
import * as THREE from 'three';

// === Embedded photogrammetry scan: 123234 triangles, 68919 vertices, with UVs ===
const TRASH_MESH = {
  vertexCount: 68919,
  triangleCount: 123234,
  indexCount: 369702,
  posMin: [-0.9121670126914978, -0.3723885416984558, -1.0],
  posRange: [1.8243340253829956, 0.7447770535945892, 2.0],
  useUint16Indices: false,
  positionBytes: 413514,
  uvBytes: 275676,
  indexBytes: 1478808,
  hasUVs: true,
  data: ''
};

const TRASH_TEXTURE_DATA_URL = 'data:image/jpeg;base64,';

function buildTrashGeometry(THREE) {
  // Decode base64
  const binStr = atob(TRASH_MESH.data);
  const bytes = new Uint8Array(binStr.length);
  for (let i = 0; i < binStr.length; i++) bytes[i] = binStr.charCodeAt(i);

  // Slice each section into its own buffer for alignment safety
  let offset = 0;
  const posBytes = bytes.slice(offset, offset + TRASH_MESH.positionBytes);
  offset += TRASH_MESH.positionBytes;

  let uvBytes = null;
  if (TRASH_MESH.hasUVs) {
    uvBytes = bytes.slice(offset, offset + TRASH_MESH.uvBytes);
    offset += TRASH_MESH.uvBytes;
  }
  const indexBytes = bytes.slice(offset, offset + TRASH_MESH.indexBytes);

  const posQuant = new Uint16Array(posBytes.buffer);
  const uvQuant = uvBytes ? new Uint16Array(uvBytes.buffer) : null;
  const indices = TRASH_MESH.useUint16Indices
    ? new Uint16Array(indexBytes.buffer)
    : new Uint32Array(indexBytes.buffer);

  // Dequantize positions
  const positions = new Float32Array(TRASH_MESH.vertexCount * 3);
  const [pmx, pmy, pmz] = TRASH_MESH.posMin;
  const [prx, pry, prz] = TRASH_MESH.posRange;
  for (let i = 0; i < TRASH_MESH.vertexCount; i++) {
    positions[i*3]     = (posQuant[i*3]     / 65535) * prx + pmx;
    positions[i*3 + 1] = (posQuant[i*3 + 1] / 65535) * pry + pmy;
    positions[i*3 + 2] = (posQuant[i*3 + 2] / 65535) * prz + pmz;
  }

  // Dequantize UVs (range 0..1)
  let uvs = null;
  if (uvQuant) {
    uvs = new Float32Array(TRASH_MESH.vertexCount * 2);
    for (let i = 0; i < TRASH_MESH.vertexCount * 2; i++) {
      uvs[i] = uvQuant[i] / 65535;
    }
  }

  const geo = new THREE.BufferGeometry();
  geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
  if (uvs) geo.setAttribute('uv', new THREE.BufferAttribute(uvs, 2));
  geo.setIndex(new THREE.BufferAttribute(indices, 1));
  // Compute normals from geometry — more reliable than transmitting them
  geo.computeVertexNormals();
  geo.computeBoundingBox();
  geo.computeBoundingSphere();
  return geo;
}

const AVATAR_DATA_URL = 'data:image/png;base64,';

export default function Portfolio() {
  const mountRef = useRef(null);
  const cursorRef = useRef(null);
  const thumbnailRef = useRef(null);
  const [time, setTime] = useState('—:—');
  const [stats, setStats] = useState({ fps: 60, tris: 0 });
  const [coords, setCoords] = useState({ x: '0.000', y: '0.000', z: '0.000' });
  const [scanActive, setScanActive] = useState(false);
  const [hoveredProject, setHoveredProject] = useState(null);

  // Salzburg time (Europe/Vienna IANA zone covers all of Austria)
  useEffect(() => {
    const update = () => {
      try {
        const fmt = new Intl.DateTimeFormat('en-GB', {
          timeZone: 'Europe/Vienna',
          hour: '2-digit',
          minute: '2-digit',
          hour12: false
        });
        setTime(fmt.format(new Date()));
      } catch (e) {
        setTime('—:—');
      }
    };
    update();
    const id = setInterval(update, 30000);
    return () => clearInterval(id);
  }, []);

  // Custom cursor follow + thumbnail position tracking
  useEffect(() => {
    const handleMove = (e) => {
      if (cursorRef.current) {
        cursorRef.current.style.transform = `translate(${e.clientX - 4}px, ${e.clientY - 4}px)`;
      }
      if (thumbnailRef.current) {
        // Offset to upper-right of cursor, with edge guards
        const tw = 240, th = 160;
        let x = e.clientX + 28;
        let y = e.clientY - th - 16;
        if (x + tw > window.innerWidth - 16) x = e.clientX - tw - 28;
        if (y < 16) y = e.clientY + 28;
        thumbnailRef.current.style.transform = `translate(${x}px, ${y}px)`;
      }
    };
    window.addEventListener('pointermove', handleMove);
    return () => window.removeEventListener('pointermove', handleMove);
  }, []);

  // Three.js scene
  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;

    const scene = new THREE.Scene();
    // No background — let the page's dark color show through for seamless integration

    const w = mount.clientWidth;
    const h = mount.clientHeight;

    const camera = new THREE.PerspectiveCamera(34, w / h, 0.1, 100);
    camera.position.set(0, 0.7, 4.6);
    camera.lookAt(0, 0, 0);

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setClearColor(0x000000, 0);
    renderer.setSize(w, h);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    mount.appendChild(renderer.domElement);

    // Lighting — soft, naturalistic. Will be replaced by HDRI environment when available.
    // Hemisphere gives a sky/ground color gradient (mimics outdoor diffuse light).
    const hemi = new THREE.HemisphereLight(0xe8eaf0, 0x2a2620, 0.7);
    scene.add(hemi);

    // Key light — casts shadows so trails ground into the trash mesh.
    // Slightly stronger now since we'll see real shadow falloff against the lit areas.
    const key = new THREE.DirectionalLight(0xfff4e6, 0.85);
    key.position.set(2, 3.5, 3);
    key.castShadow = true;
    // Shadow camera frustum — tight around the object for max resolution per pixel
    key.shadow.mapSize.set(2048, 2048);
    key.shadow.camera.near = 0.5;
    key.shadow.camera.far = 12;
    key.shadow.camera.left = -2.4;
    key.shadow.camera.right = 2.4;
    key.shadow.camera.top = 2.4;
    key.shadow.camera.bottom = -2.4;
    key.shadow.bias = -0.0006;
    key.shadow.normalBias = 0.02;
    key.shadow.radius = 4;  // PCF kernel softness
    scene.add(key);

    // Tiny ambient bump just to lift the deepest shadows
    scene.add(new THREE.AmbientLight(0xffffff, 0.18));

    // Tone mapping prevents the scan textures from blowing out
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 0.95;
    // Color space — handle both new (colorSpace) and old (encoding) Three.js APIs
    if (THREE.SRGBColorSpace !== undefined && 'outputColorSpace' in renderer) {
      renderer.outputColorSpace = THREE.SRGBColorSpace;
    } else if (THREE.sRGBEncoding !== undefined) {
      renderer.outputEncoding = THREE.sRGBEncoding;
    }

    // Trash scan — real photogrammetry geometry, decimated and quantized
    const baseGeo = buildTrashGeometry(THREE);
    // Center geometry on its bounding box and scale to a visually sensible size
    baseGeo.computeBoundingBox();
    const bbox = baseGeo.boundingBox;
    const cx = (bbox.min.x + bbox.max.x) / 2;
    const cy = (bbox.min.y + bbox.max.y) / 2;
    const cz = (bbox.min.z + bbox.max.z) / 2;
    baseGeo.translate(-cx, -cy, -cz);
    // Scale so the largest extent is about 2 units, matching previous placeholder size
    const ext = new THREE.Vector3();
    baseGeo.boundingBox.getSize(ext);
    const maxExt = Math.max(ext.x, ext.y, ext.z);
    const targetSize = 2.4;
    baseGeo.scale(targetSize / maxExt, targetSize / maxExt, targetSize / maxExt);
    baseGeo.computeBoundingBox();
    baseGeo.computeBoundingSphere();

    // Cache bounds for the scan effect — sweep through vertical extent
    const scanMin = baseGeo.boundingBox.min.y - 0.1;
    const scanMax = baseGeo.boundingBox.max.y + 0.1;

    const triCount = baseGeo.index ? baseGeo.index.count / 3 : baseGeo.attributes.position.count / 3;
    setStats(s => ({ ...s, tris: Math.round(triCount) }));

    // Main mesh — textured photogrammetry scan
    const texLoader = new THREE.TextureLoader();
    const colorMap = texLoader.load(TRASH_TEXTURE_DATA_URL);
    if (THREE.SRGBColorSpace !== undefined && 'colorSpace' in colorMap) {
      colorMap.colorSpace = THREE.SRGBColorSpace;
    } else if (THREE.sRGBEncoding !== undefined) {
      colorMap.encoding = THREE.sRGBEncoding;
    }
    colorMap.anisotropy = 4;
    colorMap.flipY = false;  // glTF convention — UVs are NOT Y-flipped
    const meshMat = new THREE.MeshStandardMaterial({
      map: colorMap,
      roughness: 0.85,
      metalness: 0.02,
      side: THREE.FrontSide
    });
    // Group everything that rotates together — mesh, wireframe, trails — so the
    // trails track the object's orientation rather than spinning in world space.
    const objectGroup = new THREE.Group();
    scene.add(objectGroup);

    const mesh = new THREE.Mesh(baseGeo, meshMat);
    mesh.receiveShadow = true;
    mesh.castShadow = true;
    objectGroup.add(mesh);

    // Wireframe with world-space scan shader
    const wireGeo = new THREE.WireframeGeometry(baseGeo);
    const scanMat = new THREE.ShaderMaterial({
      uniforms: {
        uScanY: { value: 100.0 },
        uScanWidth: { value: 0.18 },
        uColor: { value: new THREE.Color(0x00ff80) }
      },
      vertexShader: `
        varying vec3 vWorld;
        void main() {
          vec4 wp = modelMatrix * vec4(position, 1.0);
          vWorld = wp.xyz;
          gl_Position = projectionMatrix * viewMatrix * wp;
        }
      `,
      fragmentShader: `
        uniform float uScanY;
        uniform float uScanWidth;
        uniform vec3 uColor;
        varying vec3 vWorld;
        void main() {
          float d = abs(vWorld.y - uScanY);
          float v = 1.0 - smoothstep(0.0, uScanWidth, d);
          if (v < 0.01) discard;
          gl_FragColor = vec4(uColor, v);
        }
      `,
      transparent: true,
      depthWrite: false
    });
    const wireMesh = new THREE.LineSegments(wireGeo, scanMat);
    objectGroup.add(wireMesh);

    // Cube camera for real-time scene reflections — captures the trash object + page
    // and feeds the result to the chrome trails as their environment map.
    const cubeRenderTarget = new THREE.WebGLCubeRenderTarget(128, {
      format: THREE.RGBAFormat,
      generateMipmaps: true,
      minFilter: THREE.LinearMipmapLinearFilter
    });
    if (THREE.SRGBColorSpace !== undefined && 'colorSpace' in cubeRenderTarget.texture) {
      cubeRenderTarget.texture.colorSpace = THREE.SRGBColorSpace;
    }
    const cubeCamera = new THREE.CubeCamera(0.1, 50, cubeRenderTarget);
    scene.add(cubeCamera);

    // Liquid-chrome trails — thin, mirror-finish, drawing through and around the object
    const TRAIL_COUNT = 5;
    const TRAIL_HISTORY = 80;          // longer history = longer trails
    const TRAIL_TUBE_SEGMENTS = 79;
    const TRAIL_RADIAL_SEGMENTS = 5;   // few sides — they're so thin it doesn't matter
    const TRAIL_RADIUS = 0.013;        // very thin, ink-like
    const trails = [];

    for (let i = 0; i < TRAIL_COUNT; i++) {
      // Each trail picks its own "drawing plane" axis so they curve through different orientations
      const upAxis = new THREE.Vector3(
        Math.random() - 0.5,
        Math.random() - 0.5,
        Math.random() - 0.5
      ).normalize();

      // Seed initial path as a random scribble near the object
      const startPos = new THREE.Vector3(
        (Math.random() - 0.5) * 1.6,
        (Math.random() - 0.5) * 0.6,
        (Math.random() - 0.5) * 1.6
      );
      const points = [];
      for (let j = 0; j < TRAIL_HISTORY; j++) {
        points.push(startPos.clone());
      }

      // Pure chrome — fully metallic, slightly warm, picks up scene as reflection
      const mat = new THREE.MeshPhysicalMaterial({
        color: 0xffffff,
        metalness: 1.0,
        roughness: 0.04,
        envMap: cubeRenderTarget.texture,
        envMapIntensity: 1.4,
        clearcoat: 1.0,
        clearcoatRoughness: 0.02,
        side: THREE.DoubleSide
      });

      const curve = new THREE.CatmullRomCurve3(points, false, 'catmullrom', 0.5);
      const geo = new THREE.TubeGeometry(curve, TRAIL_TUBE_SEGMENTS, TRAIL_RADIUS, TRAIL_RADIAL_SEGMENTS, false);

      const mesh = new THREE.Mesh(geo, mat);
      mesh.renderOrder = 2;
      mesh.castShadow = true;
      // Trails are chrome — they don't realistically receive shadows from themselves
      mesh.receiveShadow = false;
      objectGroup.add(mesh);

      trails.push({
        mesh,
        material: mat,
        points,
        velocity: new THREE.Vector3(),
        target: startPos.clone(),
        targetTimer: 0,
        upAxis,
        seed: i * 17.3 + Math.random() * 50,
        speedScale: 0.85 + Math.random() * 0.5
      });
    }

    // Drag-to-orbit
    let isDragging = false;
    let prev = { x: 0, y: 0 };
    let targetRotY = 0;
    let currentRotY = 0;
    let targetRotX = 0;
    let currentRotX = 0;

    const onDown = (e) => {
      isDragging = true;
      prev.x = e.clientX;
      prev.y = e.clientY;
      mount.setPointerCapture(e.pointerId);
    };
    const onMove = (e) => {
      const rect = mount.getBoundingClientRect();
      const nx = ((e.clientX - rect.left) / rect.width - 0.5) * 2;
      const ny = ((e.clientY - rect.top) / rect.height - 0.5) * -2;
      setCoords({
        x: nx.toFixed(3),
        y: ny.toFixed(3),
        z: (Math.sin(performance.now() * 0.001) * 0.5).toFixed(3)
      });

      if (!isDragging) return;
      const dx = e.clientX - prev.x;
      const dy = e.clientY - prev.y;
      targetRotY += dx * 0.008;
      targetRotX = Math.max(-0.7, Math.min(0.7, targetRotX + dy * 0.008));
      prev.x = e.clientX;
      prev.y = e.clientY;
    };
    const onUp = (e) => {
      isDragging = false;
      try { mount.releasePointerCapture(e.pointerId); } catch (err) {}
    };

    mount.addEventListener('pointerdown', onDown);
    mount.addEventListener('pointermove', onMove);
    mount.addEventListener('pointerup', onUp);
    mount.addEventListener('pointercancel', onUp);

    // Resize
    const onResize = () => {
      if (!mount) return;
      const w2 = mount.clientWidth;
      const h2 = mount.clientHeight;
      camera.aspect = w2 / h2;
      camera.updateProjectionMatrix();
      renderer.setSize(w2, h2);
    };
    window.addEventListener('resize', onResize);

    // Loop
    let frameId;
    let frameCount = 0;
    let fpsLast = performance.now();
    let scanTime = 0;
    let elapsed = 0;
    let lastTime = performance.now();
    let scanWasActive = false;

    const animate = () => {
      frameId = requestAnimationFrame(animate);
      const now = performance.now();
      const dt = Math.min((now - lastTime) / 1000, 0.05);
      lastTime = now;
      elapsed += dt;
      scanTime += dt;

      frameCount++;
      if (now - fpsLast >= 1000) {
        setStats(s => ({ ...s, fps: frameCount }));
        frameCount = 0;
        fpsLast = now;
      }

      if (!isDragging) {
        targetRotY += dt * 0.18;
        targetRotX += (0 - targetRotX) * dt * 0.6;
      }
      currentRotY += (targetRotY - currentRotY) * 0.1;
      currentRotX += (targetRotX - currentRotX) * 0.1;

      // Rotate the whole group — mesh, wireframe, and trails together
      objectGroup.rotation.y = currentRotY;
      objectGroup.rotation.x = currentRotX;

      // Scan cycle — every 7.5s, 2.2s sweep
      const PERIOD = 7.5;
      const DUR = 2.2;
      const phase = scanTime % PERIOD;
      const isActive = phase < DUR;
      if (isActive !== scanWasActive) {
        setScanActive(isActive);
        scanWasActive = isActive;
      }
      if (isActive) {
        const t = phase / DUR;
        const eased = 1 - Math.pow(1 - t, 2.4);
        scanMat.uniforms.uScanY.value = scanMin + eased * (scanMax - scanMin);
      } else {
        scanMat.uniforms.uScanY.value = 100;
      }

      // Update cube camera periodically so trails reflect the actual scene.
      // Hide trails before the capture or they'll reflect each other -> infinity mirror.
      if ((frameCount + Math.floor(now/16)) % 3 === 0) {
        trails.forEach(tr => { tr.mesh.visible = false; });
        cubeCamera.update(renderer, scene);
        trails.forEach(tr => { tr.mesh.visible = true; });
      }

      // Drive trails with target-seeking + tangential bias for "drawing" gestures.
      // Each trail chases a moving target point; when close, it picks a new one.
      // A tangential force (perpendicular to outward direction) makes paths curve
      // around the object rather than just stab toward a point.
      trails.forEach((tr) => {
        const head = tr.points[tr.points.length - 1];

        // Pick a new target when reached or timer expires
        tr.targetTimer -= dt;
        if (tr.targetTimer <= 0 || head.distanceTo(tr.target) < 0.25) {
          // Random target distributed in a thin shell near the object surface
          const r = 0.6 + Math.random() * 1.0;
          const phi = Math.random() * Math.PI * 2;
          const cosTheta = (Math.random() - 0.5) * 1.4;  // bias toward equator
          const sinTheta = Math.sqrt(Math.max(0, 1 - cosTheta * cosTheta));
          tr.target.set(
            r * sinTheta * Math.cos(phi),
            r * cosTheta * 0.55,  // squash vertically since object is wider than tall
            r * sinTheta * Math.sin(phi)
          );
          tr.targetTimer = 0.18 + Math.random() * 0.45;
        }

        // Target attraction
        const toTarget = tr.target.clone().sub(head);
        const tDist = toTarget.length();
        toTarget.normalize();

        // Tangential bias — cross product gives sideways force, creating curves & loops.
        // Mix in trail's upAxis so different trails curve in different planes.
        const outward = head.clone().normalize();
        const tangent = new THREE.Vector3().crossVectors(outward, tr.upAxis).normalize();

        // Combine forces: pull toward target + lateral curve + small noise jitter
        const accel = new THREE.Vector3();
        accel.addScaledVector(toTarget, 4.0 * Math.min(tDist, 1.5));
        accel.addScaledVector(tangent, 3.2);
        // Noise jitter — high frequency for sharp turns
        const t = elapsed * 1.2 + tr.seed;
        accel.x += Math.sin(t * 2.7 + head.y * 5) * 1.2;
        accel.y += Math.cos(t * 3.1 + head.z * 4) * 0.8;
        accel.z += Math.sin(t * 2.4 + head.x * 5) * 1.2;

        tr.velocity.addScaledVector(accel, dt);

        // Damping + speed cap
        tr.velocity.multiplyScalar(0.91);
        const maxSpeed = 3.2 * tr.speedScale;
        if (tr.velocity.length() > maxSpeed) tr.velocity.setLength(maxSpeed);

        const newHead = head.clone().addScaledVector(tr.velocity, dt);
        // Soft containment within sphere — clamp if escaping
        if (newHead.length() > 1.85) newHead.setLength(1.85);

        // Shift history
        tr.points.shift();
        tr.points.push(newHead);

        // Rebuild tube
        tr.mesh.geometry.dispose();
        const curve = new THREE.CatmullRomCurve3(tr.points, false, 'catmullrom', 0.5);
        tr.mesh.geometry = new THREE.TubeGeometry(
          curve, TRAIL_TUBE_SEGMENTS, TRAIL_RADIUS, TRAIL_RADIAL_SEGMENTS, false
        );
      });

      renderer.render(scene, camera);
    };
    animate();

    return () => {
      cancelAnimationFrame(frameId);
      window.removeEventListener('resize', onResize);
      mount.removeEventListener('pointerdown', onDown);
      mount.removeEventListener('pointermove', onMove);
      mount.removeEventListener('pointerup', onUp);
      mount.removeEventListener('pointercancel', onUp);
      if (mount.contains(renderer.domElement)) {
        mount.removeChild(renderer.domElement);
      }
      renderer.dispose();
      baseGeo.dispose();
      meshMat.dispose();
      wireGeo.dispose();
      scanMat.dispose();
      trails.forEach(tr => {
        tr.mesh.geometry.dispose();
        tr.material.dispose();
      });
      cubeRenderTarget.dispose();
    };
  }, []);

  const projects = [
    { year: '2025', client: 'Red Bull', title: 'Energy Brand Campaign', role: 'Senior 3D Motion', id: '0024', tint: ['#a30418', '#1d3a8a'] },
    { year: '2024', client: 'Apple', title: 'Vision Pro App Store', role: '3D Lead, Motion, AD', id: '0023', tint: ['#1d65f0', '#0a1f4a'] },
    { year: '2024', client: 'Apple', title: 'Apps & Games Editorial', role: '3D Designer, AD', id: '0022', tint: ['#ff5d5d', '#ffb84d'] },
    { year: '2023', client: 'Apple', title: 'App Store Originals', role: '3D Design Lead', id: '0021', tint: ['#7e3eff', '#1f0a4a'] },
    { year: '2022', client: 'WarnerMedia', title: 'Win the Court', role: 'Motion Designer', id: '0020', tint: ['#1f4ec2', '#070a1a'] },
    { year: '2021', client: 'Gensler', title: 'Experiential Install (NDA)', role: 'Motion + AD', id: '0019', tint: ['#3a4a55', '#0c1014'] },
  ];

  return (
    <div
      className="min-h-screen w-full"
      style={{ fontFamily: "'IBM Plex Sans', system-ui, sans-serif", cursor: 'none', backgroundColor: '#0D0D0D', color: '#F4F2EE' }}
    >
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@400;500;600;700&family=IBM+Plex+Mono:wght@400;500&display=swap');

        html, body {
          background: #0D0D0D;
          color: #F4F2EE;
          margin: 0;
          padding: 0;
        }

        .portfolio-root {
          background: #0D0D0D;
          color: #F4F2EE;
        }

        .portfolio-root, .portfolio-root *, .portfolio-root *::before, .portfolio-root *::after {
          cursor: none !important;
        }

        /* Reliable text color classes — avoid Tailwind arbitrary-value parsing issues */
        .text-fg     { color: #F4F2EE; }
        .text-fg-90  { color: rgba(244, 242, 238, 0.90); }
        .text-fg-70  { color: rgba(244, 242, 238, 0.70); }
        .text-fg-55  { color: rgba(244, 242, 238, 0.55); }
        .text-fg-45  { color: rgba(244, 242, 238, 0.45); }
        .text-fg-30  { color: rgba(244, 242, 238, 0.30); }
        .text-fg-15  { color: rgba(244, 242, 238, 0.15); }
        .text-accent { color: #00FF80; }
        .text-accent-85 { color: rgba(0, 255, 128, 0.85); }
        .text-accent-55 { color: rgba(0, 255, 128, 0.55); }
        .text-accent-35 { color: rgba(0, 255, 128, 0.35); }
        .border-fg-12 { border-color: rgba(244, 242, 238, 0.12); }

        .mono { font-family: 'IBM Plex Mono', ui-monospace, monospace; font-feature-settings: "tnum" 1; }
        .accent { color: #00FF80; }

        @keyframes work-pulse {
          0%, 100% { transform: translateY(0); opacity: 0.55; }
          50% { transform: translateY(5px); opacity: 1; }
        }
        .work-arrow { animation: work-pulse 2.4s ease-in-out infinite; }

        @keyframes scan-blink {
          0%, 70%, 100% { opacity: 0.35; }
          35% { opacity: 1; }
        }
        .scan-indicator-active { animation: scan-blink 0.4s ease-in-out infinite; }

        .project-row .row-year, .project-row .row-title, .project-row .row-client, .project-row .row-role {
          transition: color 220ms cubic-bezier(0.65, 0, 0.35, 1);
        }
        .project-row:hover .row-year { color: #00FF80; }
        .project-row:hover .row-title { color: #F4F2EE; }
        .project-row:hover .row-client { color: #F4F2EE; }

        /* Project row — transparent by default, subtle dark backdrop with blur on hover.
           Helps text readability when 3D scene shows through. */
        .project-row {
          background-color: transparent;
          transition: background-color 200ms cubic-bezier(0.65, 0, 0.35, 1),
                      backdrop-filter 200ms cubic-bezier(0.65, 0, 0.35, 1);
          padding-left: 12px;
          padding-right: 12px;
          margin-left: -12px;
          margin-right: -12px;
        }
        .project-row:hover {
          background-color: rgba(13, 13, 13, 0.55);
          backdrop-filter: blur(8px);
          -webkit-backdrop-filter: blur(8px);
        }

        /* Hover thumbnail — follows cursor on project rows */
        .hover-thumb {
          position: fixed;
          top: 0;
          left: 0;
          width: 240px;
          height: 160px;
          pointer-events: none;
          z-index: 95;
          opacity: 0;
          transition: opacity 180ms cubic-bezier(0.65, 0, 0.35, 1);
          will-change: transform, opacity;
          border: 1px solid rgba(244, 242, 238, 0.18);
          box-shadow: 0 12px 40px rgba(0, 0, 0, 0.6);
          overflow: hidden;
        }
        .hover-thumb.visible { opacity: 1; }
        .hover-thumb-inner {
          position: absolute;
          inset: 0;
          display: flex;
          flex-direction: column;
          justify-content: space-between;
          padding: 12px;
        }

        .hover-accent { transition: color 200ms; }
        .hover-accent:hover { color: #00FF80; }

        .glow-dot {
          box-shadow: 0 0 6px #00FF80, 0 0 12px rgba(0, 255, 128, 0.4);
        }
      `}</style>

      <div className="portfolio-root" style={{ position: 'relative' }}>
        {/* Custom green dot cursor */}
        <div
          ref={cursorRef}
          className="fixed top-0 left-0 w-2 h-2 rounded-full pointer-events-none z-[100] glow-dot"
          style={{ backgroundColor: '#00FF80', willChange: 'transform' }}
        />

        {/* Hover thumbnail — follows cursor when over project rows */}
        <div
          ref={thumbnailRef}
          className={`hover-thumb ${hoveredProject ? 'visible' : ''}`}
          style={{
            background: hoveredProject
              ? `linear-gradient(135deg, ${hoveredProject.tint[0]} 0%, ${hoveredProject.tint[1]} 100%)`
              : '#222'
          }}
        >
          <div className="hover-thumb-inner">
            <div className="mono" style={{ fontSize: '9px', letterSpacing: '0.1em', color: 'rgba(255,255,255,0.7)' }}>
              {hoveredProject ? hoveredProject.client.toUpperCase() : ''}
            </div>
            <div>
              <div style={{ fontSize: '14px', color: '#fff', fontWeight: 500, lineHeight: 1.2 }}>
                {hoveredProject ? hoveredProject.title : ''}
              </div>
              <div className="mono" style={{ fontSize: '9px', color: 'rgba(255,255,255,0.55)', marginTop: '4px', letterSpacing: '0.05em' }}>
                {hoveredProject ? `${hoveredProject.year} · ${hoveredProject.role}` : ''}
              </div>
            </div>
          </div>
        </div>

        {/* === Massive background wordmark — sits behind the 3D scene === */}
        <div
          aria-hidden="true"
          style={{
            position: 'fixed',
            left: 32,
            right: 32,
            bottom: 24,
            zIndex: 0,
            pointerEvents: 'none',
            overflow: 'hidden',
          }}
        >
          <div
            style={{
              fontSize: 'clamp(120px, 22vw, 440px)',
              fontWeight: 700,
              letterSpacing: '-0.045em',
              color: '#F4F2EE',
              opacity: 0.85,
              lineHeight: 0.85,
              textAlign: 'left',
              userSelect: 'none',
            }}
          >
            <div>NICK</div>
            <div>O'MALLEY</div>
          </div>
        </div>

        {/* === Fixed full-viewport 3D scene === */}
        <div
          style={{
            position: 'fixed',
            inset: 0,
            zIndex: 1,
            pointerEvents: 'none'  // canvas itself enables pointer events below
          }}
        >
          <div
            ref={mountRef}
            className="absolute inset-0 overflow-hidden"
            style={{ pointerEvents: 'auto' }}
          />

          {/* Viewport metadata — bottom corners only now */}
          <div className="absolute bottom-5 left-8 mono text-[10px] tracking-wider pointer-events-none">
            <span className="text-accent-85">asset_001.glb</span>
            <span className="text-accent-35 ml-2">/ photogrammetry / 123k tris / textured</span>
          </div>

          <div className="absolute bottom-5 right-8 mono text-[10px] tracking-wider pointer-events-none text-accent-55">
            <span>x {coords.x}</span>
            <span className="ml-3">y {coords.y}</span>
            <span className="ml-3">z {coords.z}</span>
          </div>
        </div>

        {/* === Fixed top header — locked above scroll === */}
        <div
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            zIndex: 50,
            padding: '24px 32px',
            pointerEvents: 'none',  // dragging passes through; only nested elements opt back in
          }}
        >
          <div className="flex justify-between items-start">
            {/* Left: role only — the giant backdrop carries the name itself */}
            <div className="leading-none">
              <div className="text-fg-70" style={{ fontSize: '13px', letterSpacing: '0.01em' }}>
                Art Director · Motion Designer · 3D
              </div>
              <div className="text-fg-45" style={{ fontSize: '11px', marginTop: '4px' }}>
                Based in Salzburg
              </div>
              <img
                src={AVATAR_DATA_URL}
                alt=""
                style={{
                  width: '64px',
                  height: '64px',
                  marginTop: '14px',
                  display: 'block',
                  pointerEvents: 'none'
                }}
              />
            </div>

            {/* Right: stacked info column — time, stats, contact, links, version */}
            <div
              className="mono text-[10px] tracking-wider text-right"
              style={{ pointerEvents: 'auto', lineHeight: 1.7 }}
            >
              <div className="flex items-center gap-2 justify-end text-fg-70">
                <span className="w-[6px] h-[6px] rounded-full glow-dot inline-block" style={{ backgroundColor: '#00FF80' }} />
                <span>SZG {time} CET</span>
              </div>
              <div className="text-accent-85" style={{ marginTop: '6px' }}>
                {stats.fps} fps · {stats.tris.toLocaleString()} tris
              </div>
              <div className="text-accent-35">webgl · photogrammetry · 1k texture</div>

              {/* Spacer */}
              <div style={{ height: '20px' }} />

              {/* Contact + social */}
              <div className="text-fg-70 hover-accent">nick@nickomalley.net</div>
              <div className="text-fg-55 hover-accent">LinkedIn</div>
              <div className="text-fg-55 hover-accent">Instagram</div>
              <div className="text-fg-55 hover-accent">Scraps</div>
              <div className="text-fg-55 hover-accent">Info</div>

              {/* Spacer */}
              <div style={{ height: '20px' }} />

              {/* Version footer info */}
              <div className="text-fg-30">nickomalley.net / v0.1</div>
              <div className="text-fg-30">2026 · built with three.js</div>
            </div>
          </div>
        </div>

        {/* === Scrollable content layer above the 3D === */}
        <div style={{ position: 'relative', zIndex: 2 }}>

          {/* Hero spacer — fills first viewport so 3D is alone, scroll indicator at bottom */}
          <section
            className="relative flex flex-col justify-end items-center pb-12"
            style={{ minHeight: 'calc(100vh - 90px)' }}
          >
            <div className="text-center">
              <div className="mono text-[11px] accent tracking-[0.2em] mb-2 uppercase">work</div>
              <div className="work-arrow text-2xl accent leading-none">↓</div>
            </div>
          </section>

          {/* Project list — scrolls up over the 3D scene */}
          <section className="px-8 md:px-12 pb-16 pt-12">
            <div className="mono text-[10px] tracking-[0.18em] text-fg-30 mb-6 flex justify-between uppercase">
              <span>Selected Work</span>
              <span>{projects.length} entries</span>
            </div>
            <div>
              {projects.map((p) => (
                <div
                  key={p.id}
                  className="project-row relative grid grid-cols-12 gap-4 py-4 group items-baseline"
                  onMouseEnter={() => setHoveredProject(p)}
                  onMouseLeave={() => setHoveredProject(null)}
                >
                  <div className="col-span-3 text-[15px] font-medium tracking-tight row-client text-fg-90">{p.client}</div>
                  <div className="col-span-6 text-[15px] row-title text-fg-70">{p.title}</div>
                  <div className="col-span-3 text-[13px] row-role text-fg-45 text-right">{p.role}</div>
                </div>
              ))}
            </div>
          </section>

        </div>
      </div>
    </div>
  );
}
